import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { matchesSearchQuery } from './search';

describe('matchesSearchQuery', () => {
  const note = {
    title: 'Meeting notes',
    content: 'Discuss project timeline and budget',
    tags: ['work', 'meeting']
  };

  beforeEach(() => {
    // reset anything if needed
  });

  afterEach(() => {
    vi.clearAllMocks();
  });

  it('should handle happy path: return true when query matches title', () => {
    const result = matchesSearchQuery(note, 'meeting');
    expect(result).toBe(true);
  });

  it('should handle happy path: return true when query matches content', () => {
    const result = matchesSearchQuery(note, 'budget');
    expect(result).toBe(true);
  });

  it('should handle happy path: return false when query does not match', () => {
    const result = matchesSearchQuery(note, 'holiday');
    expect(result).toBe(false);
  });

  it('should handle edge case: query is empty string', () => {
    const result = matchesSearchQuery(note, '');
    expect(result).toBe(true);
  });

  it('should handle edge case: note has empty title and content but query matches tags', () => {
    const emptyNote = { title: '', content: '', tags: ['urgent'] };
    const result = matchesSearchQuery(emptyNote, 'urgent');
    expect(result).toBe(true);
  });

  it('should handle edge case: note has null fields', () => {
    const nullNote = { title: null as any, content: null as any, tags: null as any };
    const result = matchesSearchQuery(nullNote, 'any');
    expect(result).toBe(false);
  });

  it('should handle null/empty: note is null', () => {
    const result = matchesSearchQuery(null as any, 'test');
    expect(result).toBe(false);
  });

  it('should handle null/empty: query is null', () => {
    const result = matchesSearchQuery(note, null as any);
    expect(result).toBe(false);
  });

  it('should handle null/empty: both note and query are empty', () => {
    const emptyNote = { title: '', content: '', tags: [] };
    const result = matchesSearchQuery(emptyNote, '');
    expect(result).toBe(true);
  });
});

